CustomField.formula:
IF(Compliance_Status__c = 'Inactive Candidate',IMAGE("/resource/Img/I.png", ""),
   IF(Compliance_Status__c='Borrowed Temp',IMAGE("/resource/Img/B.png", ""),
      IF(Compliance_Status__c='Compliant',IMAGE("/resource/Img/C.png", ""),
	     IF(Compliance_Status__c='Partial Compliant',IMAGE("/resource/Img/P.png", ""),
		    IF(Compliance_Status__c='Not Compliant',IMAGE("/resource/Img/N.png", ""),
			   "Error"
			  )
		   )
		)
      )
  )
